238:             log.trace("Partition {} for topic {} switched by a concurrent append, retrying",
239:                     partitionInfo.partition(), topic);
240:             return true;
241:         }
242: 
243:         // We might have disabled partition switch if the queue had incomplete batches.
244:         // Check if all batches are full now and switch .
245:         if (allBatchesFull(deque)) {
246:             topicInfo.builtInPartitioner.updatePartitionInfo(partitionInfo, 0, cluster, true);
247:             if (topicInfo.builtInPartitioner.isPartitionChanged(partitionInfo)) {
248:                 log.trace("Completed previously disabled switch for topic {} partition {}, retrying",
249:                         topic, partitionInfo.partition());
